:root{
--avnav-widget-color: black;
--avnav-widget-fore-color: white;
--avnav-widget-head-color: #242323;
--layout-dark-icon-filter: var(--avnav-filter-white);
--layout-dark-widget-color: var(--avnav-widget-fore-color);
}
/* must be more specific then the color definitions below */
.nightMode{
--avnav-widget-fore-color: rgb(252 11 11 / 60%);
--layout-dark-icon-filter: var(--avnav-filter-red);
}

/*
  be sure to have a night mode definition that is more specific
  then the color classes below
  This ensures red color for all widgets in night mode
  If you do not want this, remove the rule
*/
.app.nightMode .widget{
  --avnav-widget-fore-color: rgb(252 11 11 / 60%);
  --layout-dark-widget-color: var(--avnav-widget-fore-color);
}

/* color the widget icons
   to change the icon color also to the fore color you would need to add filters
   to the color classes above*/
.widget .icon{
  filter: var(--layout-dark-icon-filter);
}
.widget{
  color: var(--layout-dark-widget-color);
}

.buttonContainer.main{
  background-color: var(--avnav-widget-color);
}
/* color classes for the widgets
   Assign one of those classes to a widget to use the color a the widget foreground color.
   If you want new colors just add classes for them here.
   To edit a color you can select the color string and klick the "Color" button.
   When done with the color editor the selection will be replaced with the changed color.
   */
.orange {
  --layout-dark-widget-color: rgba(255, 165, 0, 1);
}
.maroon {
  --layout-dark-widget-color: maroon;
}
.red {
  --layout-dark-widget-color: red;
}
.light-red {
  --layout-dark-widget-color: #ff8c8c;
}
.purple{
  --layout-dark-widget-color: purple;
}
.light-purple{
  --layout-dark-widget-color: #fb90fb;
}   
.fuchsia{
  --layout-dark-widget-color: fuchsia;
}
.green{
  --layout-dark-widget-color: green;
}
.lime{
  --layout-dark-widget-color: lime;
}
.olive{
  --layout-dark-widget-color: olive;
}
.yellow{
  --layout-dark-widget-color: yellow;
}
.navy{
  --layout-dark-widget-color: navy;
}
.blue{
  --layout-dark-widget-color: blue;
}
.light-blue{
  --layout-dark-widget-color: #8484ff;
}
.teal{
  --layout-dark-widget-color: teal;
}
.aqua{
  --layout-dark-widget-color: aqua;
}

/* Tt is also possible to set a color directly for a widget.
   This way it would always be colored without
   adding a color class.
   But to change the color you would need to edit here.
*/
/*
.widget.SOG{
  --layout-dark-widget-color: fuchsia;
} 
*/

/* a base value for the font-size of caption and unit
   the em refer to a base value of 21px being scaled down 
   if height or width are lower 600px. 
   Additionally AvNav sets a factor from the head 
   font size to caption and unit.
   */
:root{
  --head-base-fs: 2.3em;
}


/* a "modern" CSS class for widgets on dashboard pages
   that avoids the color and frame for the head
   and has much larger caption and unit */
.hfield .widgetContainer .widget .widgetHead {
    border-bottom: unset;
    border-top: 2px solid var(--avnav-widget-fore-color);
    background-color: unset;
    height: unset ;
    font-size: var(--head-base-fs);
    font-weight: 600;
}
.hfield .widgetContainer .widget .widgetData {
    font-weight: 600;
}

/* an additional CSS class "half" to be used for smaller caption and unit */
.hfield .widgetContainer .widget.half .widgetHead {
    font-size: calc(var(--head-base-fs) / 2);
}


/* a CSS class "centered" for centered text in widgets */
.widget.centered .widgetData{
  margin-right: auto;
}
